import { useState, useEffect } from 'react';
import { Layout, ConfigProvider, theme, Grid } from 'antd';
import { Outlet } from 'react-router-dom';
import Sidebar from './Sidebar';
import Header from './Header';
import ChatbotWidget from '../chatbot/ChatbotWidget';
import { useThemeMode } from '../../context/ThemeContext';

const { Content } = Layout;
const { useBreakpoint } = Grid;

const DashboardLayout = () => {
    const { mode } = useThemeMode();
    const screens = useBreakpoint();
    const [mobileSidebarOpen, setMobileSidebarOpen] = useState(false);
    const [desktopCollapsed, setDesktopCollapsed] = useState(false);

    // Responsive breakpoints
    const isMobile = !screens.md; // < 768px
    const isTablet = screens.md && !screens.xl; // 768px - 1199px
    const isDesktop = screens.xl; // >= 1200px

    // Auto-collapse sidebar on tablet
    useEffect(() => {
        // eslint-disable-next-line react-hooks/set-state-in-effect
        if (isTablet && !desktopCollapsed) {
            setDesktopCollapsed(true);
        // eslint-disable-next-line react-hooks/set-state-in-effect
        } else if (isDesktop && desktopCollapsed) {
            setDesktopCollapsed(false);
        }
    }, [isTablet, isDesktop, desktopCollapsed]);

    const toggleMobileSidebar = () => setMobileSidebarOpen(!mobileSidebarOpen);

    // Calculate content margin based on screen size and sidebar state
    const getContentMargin = () => {
        if (isMobile) return 0;
        if (isTablet || desktopCollapsed) return 80;
        return 240;
    };

    const algorithm = mode === 'dark' ? theme.darkAlgorithm : theme.defaultAlgorithm;

    return (
        <ConfigProvider
            theme={{
                algorithm,
                token: {
                    colorPrimary: '#0052CC',
                    fontFamily: 'Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif',
                    borderRadius: 8,
                    colorBgLayout: mode === 'dark' ? '#0d1117' : '#f4f5f7',
                    colorBgContainer: mode === 'dark' ? '#161b22' : '#ffffff',
                },
                components: {
                    Card: {
                        borderRadiusLG: 12,
                    },
                    Button: {
                        borderRadius: 8,
                    },
                },
            }}
        >
            <Layout style={{ minHeight: '100vh' }}>
                <Header onMenuClick={toggleMobileSidebar} />
                <Layout style={{ marginTop: 60 }}>
                    <Sidebar
                        mobileOpen={mobileSidebarOpen}
                        setMobileOpen={setMobileSidebarOpen}
                        collapsed={desktopCollapsed}
                        setCollapsed={setDesktopCollapsed}
                    />
                    <Content
                        style={{
                            marginLeft: getContentMargin(),
                            padding: isMobile ? 12 : isTablet ? 16 : 24,
                            minHeight: 'calc(100vh - 60px)',
                            transition: 'margin-left 0.25s cubic-bezier(0.4, 0, 0.2, 1), padding 0.2s ease',
                            overflow: 'auto',
                            background: mode === 'dark'
                                ? 'linear-gradient(135deg, #0d1117 0%, #161b22 100%)'
                                : 'linear-gradient(135deg, #f8f9fa 0%, #f0f2f5 100%)',
                        }}
                    >
                        <div className="scale-in">
                            <Outlet />
                        </div>
                    </Content>
                </Layout>
            </Layout>
            <ChatbotWidget />
        </ConfigProvider>
    );
};

export default DashboardLayout;

import { useState, useEffect } from 'react';
import { Card, Row, Col, Button, Select, Space, Empty, Spin, message, Tooltip, Tabs } from 'antd';
import { PlusOutlined, BgColorsOutlined, BulbFilled, BarChartOutlined } from '@ant-design/icons';
import { useProject } from '../../context/ProjectContext';
import epicService from '../../services/epicService';
import CreateEpicModal from './CreateEpicModal';
import EpicTimeline from './EpicTimeline';
import MonthCard from './MonthCard';
import MonthlyInsights from './MonthlyInsights';
import { generateMonthlyProgressData } from '../../utils/monthlyProgressData';
import './RoadmapPage.css';

const RoadmapPage = () => {
    const { currentProject } = useProject();
    const [epics, setEpics] = useState([]);
    const [loading, setLoading] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [statusFilter, setStatusFilter] = useState('all');
    const [timeRange, setTimeRange] = useState('6months');
    const [isGeneratingAI, setIsGeneratingAI] = useState(false);
    const [monthlyData, setMonthlyData] = useState(null);
    const [activeTab, setActiveTab] = useState('progress'); // 'progress' or 'epics'

    // Fetch epics
    const fetchEpics = async () => {
        if (!currentProject) return;

        setLoading(true);
        try {
            const data = await epicService.getEpicsByProject(currentProject._id);
            setEpics(Array.isArray(data) ? data : []);
        } catch (error) {
            console.error('Failed to fetch epics:', error);
            message.error('Failed to load epics');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchEpics();
        // Load monthly progress data
        const data = generateMonthlyProgressData();
        setMonthlyData(data);
    }, [currentProject]);

    // Handle create epic
    const handleCreateEpic = async (epicData) => {
        try {
            const newEpic = await epicService.createEpic({
                ...epicData,
                project: currentProject._id
            });
            setEpics([...epics, newEpic]);
            message.success(`Epic "${epicData.name}" created successfully`);
            setIsModalOpen(false);
        } catch (error) {
            console.error('Failed to create epic:', error);
            message.error('Failed to create epic');
        }
    };

    // Handle AI Generate Roadmap
    const handleGenerateAIRoadmap = async () => {
        setIsGeneratingAI(true);
        try {
            // Mock AI response - replace with real OpenAI API call in Phase 2
            const aiGeneratedEpics = generateMockAIEpics();
            
            // Add AI-generated epics to the list
            for (const epicData of aiGeneratedEpics) {
                try {
                    const newEpic = await epicService.createEpic({
                        ...epicData,
                        project: currentProject._id
                    });
                    setEpics(prev => [...prev, newEpic]);
                } catch (err) {
                    console.error('Failed to add AI epic:', err);
                }
            }
            message.success(`Generated ${aiGeneratedEpics.length} epic suggestions from AI`);
        } catch (error) {
            console.error('Failed to generate roadmap:', error);
            message.error('Failed to generate roadmap');
        } finally {
            setIsGeneratingAI(false);
        }
    };

    // Mock AI Epic Generation (Phase 2: Replace with OpenAI API)
    const generateMockAIEpics = () => {
        const now = new Date();
        const getMonthString = (offset) => {
            const date = new Date(now.getFullYear(), now.getMonth() + offset, 1);
            return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
        };

        return [
            {
                name: 'Q1 - Core Infrastructure',
                description: 'Build foundational APIs and database layer',
                start_date: getMonthString(0),
                end_date: getMonthString(3),
                status: 'IN_PROGRESS',
                owner: 'Tech Lead'
            },
            {
                name: 'Q1/Q2 - UI/UX Redesign',
                description: 'Modernize user interface with new design system',
                start_date: getMonthString(1),
                end_date: getMonthString(4),
                status: 'PLANNED',
                owner: 'Design Team'
            },
            {
                name: 'Q2 - Analytics Dashboard',
                description: 'Real-time analytics and reporting features',
                start_date: getMonthString(3),
                end_date: getMonthString(5),
                status: 'PLANNED',
                owner: 'Product Team'
            },
            {
                name: 'Q2/Q3 - Mobile App',
                description: 'Native iOS and Android applications',
                start_date: getMonthString(4),
                end_date: getMonthString(7),
                status: 'PLANNED',
                owner: 'Mobile Team'
            },
            {
                name: 'Q3 - AI Integration',
                description: 'OpenAI/LLM features and automation',
                start_date: getMonthString(6),
                end_date: getMonthString(8),
                status: 'PLANNED',
                owner: 'AI Team'
            }
        ];
    };

    // Filter epics
    const filteredEpics = epics.filter(epic => {
        if (statusFilter !== 'all' && epic.status !== statusFilter) {
            return false;
        }
        return true;
    });

    if (!currentProject) {
        return <Empty description="Please select a project first" style={{ marginTop: 50 }} />;
    }

    // Get months to display based on timeRange
    const getDisplayMonths = () => {
        if (!monthlyData) return [];
        if (timeRange === '6months') return monthlyData.months;
        if (timeRange === '12months') return monthlyData.months.slice(0, 12);
        return monthlyData.months;
    };

    const displayMonths = getDisplayMonths();

    return (
        <div className="roadmap-page">
            {/* Header */}
            <div className="roadmap-header">
                <div>
                    <h1>Product Roadmap</h1>
                    <p className="text-secondary">{currentProject.name} — Progress Timeline</p>
                </div>
                <Space>
                    <Tooltip title="Generate roadmap using AI">
                        <Button
                            type="default"
                            icon={<BulbFilled />}
                            onClick={handleGenerateAIRoadmap}
                            loading={isGeneratingAI}
                        >
                            AI Generate
                        </Button>
                    </Tooltip>
                    <Button
                        type="primary"
                        icon={<PlusOutlined />}
                        onClick={() => setIsModalOpen(true)}
                    >
                        Create Epic
                    </Button>
                </Space>
            </div>

            {/* Tabs: Progress Timeline vs Epic View */}
            <Tabs
                activeKey={activeTab}
                onChange={setActiveTab}
                items={[
                    {
                        key: 'progress',
                        label: (
                            <span>
                                <BarChartOutlined />
                                Progress Timeline
                            </span>
                        ),
                        children: (
                            <>
                                {/* Progress Controls */}
                                <Card className="roadmap-controls" style={{ marginBottom: 24 }}>
                                    <Row gutter={[16, 16]} align="middle">
                                        <Col xs={24} sm={12} md={8}>
                                            <label className="control-label">Time Range</label>
                                            <Select
                                                value={timeRange}
                                                onChange={setTimeRange}
                                                options={[
                                                    { label: '6 Months', value: '6months' },
                                                    { label: '12 Months', value: '12months' },
                                                    { label: 'All Time', value: 'all' }
                                                ]}
                                                style={{ width: '100%' }}
                                            />
                                        </Col>
                                    </Row>
                                </Card>

                                {/* Insights */}
                                {monthlyData && <MonthlyInsights monthsData={monthlyData} />}

                                {/* Monthly Progress Timeline */}
                                <div className="roadmap-divider">
                                    <h2>Monthly Progress</h2>
                                </div>

                                {loading ? (
                                    <Spin size="large" />
                                ) : displayMonths.length > 0 ? (
                                    <Row gutter={[16, 16]} className="months-grid">
                                        {displayMonths.map((month, idx) => (
                                            <Col xs={24} sm={12} md={8} lg={6} key={idx}>
                                                <MonthCard
                                                    month={month}
                                                    onTaskClick={(task) => {
                                                        message.info(`Selected: ${task.name}`);
                                                    }}
                                                />
                                            </Col>
                                        ))}
                                    </Row>
                                ) : (
                                    <Empty description="No monthly data" style={{ marginTop: 50 }} />
                                )}
                            </>
                        )
                    },
                    {
                        key: 'epics',
                        label: (
                            <span>
                                <BgColorsOutlined />
                                Epic View
                            </span>
                        ),
                        children: (
                            <>
                                {/* Epic Controls */}
                                <Card className="roadmap-controls" style={{ marginBottom: 24 }}>
                                    <Row gutter={[16, 16]} align="middle">
                                        <Col xs={24} sm={12} md={6}>
                                            <label className="control-label">Status Filter</label>
                                            <Select
                                                value={statusFilter}
                                                onChange={setStatusFilter}
                                                options={[
                                                    { label: 'All Statuses', value: 'all' },
                                                    { label: 'Planned', value: 'PLANNED' },
                                                    { label: 'In Progress', value: 'IN_PROGRESS' },
                                                    { label: 'Done', value: 'DONE' }
                                                ]}
                                                style={{ width: '100%' }}
                                            />
                                        </Col>
                                        <Col xs={24} sm={12} md={6}>
                                            <label className="control-label">Time Range</label>
                                            <Select
                                                value={timeRange}
                                                onChange={setTimeRange}
                                                options={[
                                                    { label: '6 Months', value: '6months' },
                                                    { label: '12 Months', value: '12months' },
                                                    { label: 'All Time', value: 'all' }
                                                ]}
                                                style={{ width: '100%' }}
                                            />
                                        </Col>
                                        <Col xs={24} sm={12} md={12}>
                                            <div className="legend">
                                                <span className="legend-item">
                                                    <span className="legend-color" style={{ backgroundColor: '#8c8c8c' }}></span>
                                                    Planned
                                                </span>
                                                <span className="legend-item">
                                                    <span className="legend-color" style={{ backgroundColor: '#1890ff' }}></span>
                                                    In Progress
                                                </span>
                                                <span className="legend-item">
                                                    <span className="legend-color" style={{ backgroundColor: '#52c41a' }}></span>
                                                    Done
                                                </span>
                                            </div>
                                        </Col>
                                    </Row>
                                </Card>

                                {/* Epic Timeline */}
                                <Spin spinning={loading}>
                                    {filteredEpics.length > 0 ? (
                                        <EpicTimeline
                                            epics={filteredEpics}
                                            timeRange={timeRange}
                                            onEpicUpdate={fetchEpics}
                                        />
                                    ) : (
                                        <Empty
                                            description={statusFilter === 'all' ? 'No epics yet' : `No ${statusFilter.toLowerCase()} epics`}
                                            style={{ marginTop: 50 }}
                                        />
                                    )}
                                </Spin>
                            </>
                        )
                    }
                ]}
                style={{ background: '#fff' }}
            />

            {/* Create Epic Modal */}
            <CreateEpicModal
                open={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSubmit={handleCreateEpic}
            />
        </div>
    );
};

export default RoadmapPage;

import React, { useState, useEffect } from 'react';
import {
    Card, Button, Table, Modal, Spin, message, Badge, Tooltip,
    Row, Col, Statistic, Tag, Space, Alert, Divider, Progress
} from 'antd';
import {
    CheckCircleOutlined, WarningOutlined, UserOutlined,
    TeamOutlined, RiseOutlined, LoadingOutlined, ThunderboltOutlined,
    SwapOutlined
} from '@ant-design/icons';
import api from '../../services/api';

const SmartReassignmentDashboard = ({ sprintId }) => {
    const [loading, setLoading] = useState(false);
    const [teamAnalysis, setTeamAnalysis] = useState(null);
    const [recommendations, setRecommendations] = useState([]);
    const [selectedTask, setSelectedTask] = useState(null);
    const [showRecommendationModal, setShowRecommendationModal] = useState(false);
    const [currentRecommendation, setCurrentRecommendation] = useState(null);
    const [approving, setApproving] = useState(false);
    const [requiresConfirmation, setRequiresConfirmation] = useState(false);

    // Fetch team analysis and recommendations
    const fetchAnalysis = async () => {
        try {
            setLoading(true);

            // Get team workload analysis (works with or without sprintId)
            const analysisRes = await api.get('/reassignment/team/analysis', {
                params: { sprintId: sprintId || '' }
            });

            setTeamAnalysis(analysisRes.data.data);
            console.log('Team analysis loaded:', analysisRes.data.data);

            // Get batch recommendations for overloaded employees
            try {
                const recRes = await api.post('/reassignment/batch-analyze', {
                    sprintId: sprintId || ''
                });

                setRecommendations(recRes.data.data?.reassignmentOpportunities || []);
                console.log('Recommendations loaded:', recRes.data.data?.reassignmentOpportunities);
            } catch (recError) {
                // If user doesn't have permission to see recommendations, just show team analysis
                if (recError.response?.status === 403) {
                    console.log('User does not have permission to view reassignment recommendations');
                    setRecommendations([]);
                } else {
                    throw recError;
                }
            }
        } catch (error) {
            console.error('Error fetching analysis:', error);
            message.error('Failed to fetch workload analysis: ' + (error.response?.data?.message || error.message));
        } finally {
            setLoading(false);
        }
    };

    // Get recommendation for a specific task
    const getTaskRecommendation = async (taskId) => {
        try {
            setLoading(true);
            const res = await api.get(`/reassignment/${taskId}/recommend`);

            if (!res.data.success) {
                message.warning(res.data.message);
                return;
            }

            setCurrentRecommendation(res.data.data);
            setShowRecommendationModal(true);
        } catch (error) {
            console.error('Error getting recommendation:', error);
            message.error('Failed to get recommendation');
        } finally {
            setLoading(false);
        }
    };

    // Execute reassignment
    const handleReassign = async () => {
        if (!currentRecommendation) return;

        try {
            setApproving(true);

            const response = await api.post(
                `/reassignment/${selectedTask._id}/execute`,
                {
                    newAssigneeId: currentRecommendation.recommendation.employeeId,
                    requiresConfirmation
                }
            );

            if (response.data.success) {
                message.success('Task reassigned successfully!');
                setShowRecommendationModal(false);
                setCurrentRecommendation(null);
                setRequiresConfirmation(false);
                fetchAnalysis(); // Refresh data
            } else if (response.data.requiresConfirmation) {
                setRequiresConfirmation(true);
                message.info('High-priority task requires confirmation');
            }
        } catch (error) {
            console.error('Error executing reassignment:', error);
            message.error(error.response?.data?.message || 'Failed to execute reassignment');
        } finally {
            setApproving(false);
        }
    };

    useEffect(() => {
        fetchAnalysis();
    }, [sprintId]);

    const overloadedColumns = [
        {
            title: 'Employee Name',
            dataIndex: ['name'],
            key: 'name',
            render: (text) => (
                <Space>
                    <UserOutlined />
                    <strong>{text}</strong>
                </Space>
            )
        },
        {
            title: 'Role',
            dataIndex: ['role'],
            key: 'role',
            render: (role) => <Tag color="blue">{role}</Tag>
        },
        {
            title: 'Workload',
            dataIndex: ['workloadPercentage'],
            key: 'workload',
            render: (percentage) => (
                <Space direction="vertical" style={{ width: '100%' }}>
                    <Progress
                        percent={percentage}
                        status={percentage > 80 ? 'exception' : percentage > 60 ? 'active' : 'normal'}
                        size="small"
                        format={(percent) => `${percent}%`}
                    />
                    <span style={{ fontSize: '12px', color: '#666' }}>
                        {`${percentage}% of capacity`}
                    </span>
                </Space>
            ),
            width: 150
        },
        {
            title: 'Tasks Assigned',
            dataIndex: ['assignedTasks'],
            key: 'tasks',
            render: (tasks) => (
                <Badge count={tasks} showZero style={{ backgroundColor: '#ff4d4f' }} />
            )
        },
        {
            title: 'Hours',
            dataIndex: ['assignedHours'],
            key: 'hours',
            render: (hours) => <span>{hours}h</span>
        }
    ];

    const recommendationColumns = [
        {
            title: 'Task',
            dataIndex: ['taskTitle'],
            key: 'task',
            render: (text) => <strong>{text}</strong>
        },
        {
            title: 'Current Assignee',
            dataIndex: ['currentAssignee', 'name'],
            key: 'assignee',
            render: (text, record) => (
                <Space direction="vertical" size={0}>
                    <span>{text}</span>
                    <span style={{ fontSize: '12px', color: '#999' }}>
                        {record.currentAssignee.workloadPercentage}% overloaded
                    </span>
                </Space>
            )
        },
        {
            title: 'Recommended Employee',
            dataIndex: ['recommendation', 'name'],
            key: 'recommended',
            render: (text, record) => (
                <Space direction="vertical" size={0}>
                    <span style={{ fontWeight: 'bold', color: '#1890ff' }}>
                        {text}
                    </span>
                    <span style={{ fontSize: '12px', color: '#666' }}>
                        Workload: {record.recommendation.currentWorkloadPercentage}%
                    </span>
                    <span style={{ fontSize: '12px', color: '#666' }}>
                        Skills: {record.recommendation.skillMatchPercentage}% match
                    </span>
                </Space>
            )
        },
        {
            title: 'Score',
            dataIndex: ['score'],
            key: 'score',
            render: (score) => (
                <Tooltip title={`Recommendation confidence: ${score}%`}>
                    <Tag color={score > 80 ? 'green' : score > 60 ? 'orange' : 'red'}>
                        {score}%
                    </Tag>
                </Tooltip>
            )
        },
        {
            title: 'Action',
            key: 'action',
            render: (_, record) => (
                <Button
                    type="primary"
                    size="small"
                    icon={<SwapOutlined />}
                    onClick={() => {
                        setSelectedTask({ _id: record.taskId });
                        getTaskRecommendation(record.taskId);
                    }}
                >
                    Review & Reassign
                </Button>
            )
        }
    ];

    if (loading && !teamAnalysis) {
        return (
            <Card>
                <Spin indicator={<LoadingOutlined style={{ fontSize: 48 }} spin />} />
            </Card>
        );
    }

    const summary = teamAnalysis?.summary || {};
    const overloaded = teamAnalysis?.details?.overloaded || [];
    const balanced = teamAnalysis?.details?.balanced || [];
    const underutilized = teamAnalysis?.details?.underutilized || [];
    const totalMembers = summary.totalEmployees || 0;

    return (
        <div style={{ padding: '24px' }}>
            {/* No data message */}
            {!loading && totalMembers === 0 && (
                <Card
                    style={{
                        textAlign: 'center',
                        padding: '48px 24px',
                        color: '#8c8c8c'
                    }}
                >
                    <TeamOutlined style={{ fontSize: '48px', marginBottom: '16px' }} />
                    <p style={{ fontSize: '16px', marginBottom: '8px' }}>No team data available</p>
                    <p style={{ fontSize: '14px', color: '#bfbfbf' }}>
                        Make sure there's an active sprint with assigned tasks and team members
                    </p>
                    <Button type="primary" onClick={fetchAnalysis} style={{ marginTop: '16px' }}>
                        Refresh
                    </Button>
                </Card>
            )}

            {/* Data content */}
            {totalMembers > 0 && (<Card
                title={
                    <Space>
                        <ThunderboltOutlined style={{ color: '#1890ff' }} />
                        <span>Smart Reassignment Assistant</span>
                    </Space>
                }
                extra={
                    <Button type="primary" onClick={fetchAnalysis} loading={loading}>
                        Refresh Analysis
                    </Button>
                }
                style={{ marginBottom: '24px' }}
            >
                {/* Summary Statistics */}
                <Row gutter={16} style={{ marginBottom: '24px' }}>
                    <Col xs={24} sm={12} lg={6}>
                        <Statistic
                            title="Team Size"
                            value={summary.totalEmployees || 0}
                            prefix={<TeamOutlined />}
                        />
                    </Col>
                    <Col xs={24} sm={12} lg={6}>
                        <Statistic
                            title="Average Workload"
                            value={summary.avgWorkload || 0}
                            suffix="%"
                            valueStyle={{
                                color: summary.avgWorkload > 60 ? '#ff4d4f' : '#52c41a'
                            }}
                        />
                    </Col>
                    <Col xs={24} sm={12} lg={6}>
                        <Statistic
                            title="Overloaded"
                            value={summary.overloadedCount || 0}
                            prefix={<WarningOutlined style={{ color: '#ff4d4f' }} />}
                        />
                    </Col>
                    <Col xs={24} sm={12} lg={6}>
                        <Statistic
                            title="Opportunities"
                            value={recommendations.length}
                            prefix={<CheckCircleOutlined style={{ color: '#52c41a' }} />}
                        />
                    </Col>
                </Row>

                <Divider />

                {/* Alert for overloaded team */}
                {summary.overloadedCount > 0 && (
                    <Alert
                        message="Team Imbalance Detected"
                        description={`${summary.overloadedCount} team member(s) are overloaded. Use reassignment recommendations to balance workload.`}
                        type="warning"
                        icon={<WarningOutlined />}
                        showIcon
                        style={{ marginBottom: '24px' }}
                    />
                )}

                {/* Overloaded Team Members */}
                <h3 style={{ marginTop: '24px' }}>
                    <Badge count={overloaded.length} style={{ marginRight: '8px' }} />
                    Overloaded Team Members ({'>'}60%)
                </h3>
                <Table
                    dataSource={overloaded}
                    columns={overloadedColumns}
                    pagination={{ pageSize: 5 }}
                    size="small"
                    rowKey="employeeId"
                    style={{ marginBottom: '24px' }}
                />

                {/* Balanced Team Members */}
                {balanced.length > 0 && (
                    <>
                        <h3 style={{ marginTop: '24px' }}>
                            <Badge count={balanced.length} style={{ marginRight: '8px' }} color="green" />
                            Balanced Workload (35-60%)
                        </h3>
                        <Table
                            dataSource={balanced}
                            columns={overloadedColumns}
                            pagination={{ pageSize: 5 }}
                            size="small"
                            rowKey="employeeId"
                            style={{ marginBottom: '24px' }}
                        />
                    </>
                )}

                {/* Underutilized Team Members */}
                {underutilized.length > 0 && (
                    <>
                        <h3 style={{ marginTop: '24px' }}>
                            <Badge count={underutilized.length} style={{ marginRight: '8px' }} color="blue" />
                            Underutilized ({`<`}35%)
                        </h3>
                        <Table
                            dataSource={underutilized}
                            columns={overloadedColumns}
                            pagination={{ pageSize: 5 }}
                            size="small"
                            rowKey="employeeId"
                        />
                    </>
                )}
            </Card>
            )}

            {/* Reassignment Opportunities */}
            {recommendations.length > 0 && (
                <Card
                    title={
                        <Space>
                            <RiseOutlined style={{ color: '#52c41a' }} />
                            <span>Reassignment Opportunities ({recommendations.length})</span>
                        </Space>
                    }
                    style={{ marginBottom: '24px' }}
                >
                    <Table
                        dataSource={recommendations}
                        columns={recommendationColumns}
                        pagination={{ pageSize: 10 }}
                        size="small"
                        rowKey="taskId"
                    />
                </Card>
            )}

            {/* Recommendation Modal */}
            <Modal
                title="Review Reassignment Recommendation"
                open={showRecommendationModal}
                onCancel={() => {
                    setShowRecommendationModal(false);
                    setCurrentRecommendation(null);
                    setRequiresConfirmation(false);
                }}
                footer={[
                    <Button key="cancel" onClick={() => setShowRecommendationModal(false)}>
                        Cancel
                    </Button>,
                    <Button
                        key="submit"
                        type="primary"
                        loading={approving}
                        onClick={handleReassign}
                    >
                        {requiresConfirmation ? 'Confirm & Reassign' : 'Reassign Task'}
                    </Button>
                ]}
                width={700}
            >
                {currentRecommendation && (
                    <Space direction="vertical" style={{ width: '100%' }} size="large">
                        {/* Reason */}
                        <Alert
                            message="Recommendation Reason"
                            description={currentRecommendation.reason}
                            type="info"
                            showIcon
                        />

                        <Divider />

                        {/* Current Assignee */}
                        <div>
                            <h4>Current Assignee</h4>
                            <Space direction="vertical" size={0}>
                                <span><strong>{currentRecommendation.currentAssignee.name}</strong></span>
                                <Progress
                                    percent={currentRecommendation.currentAssignee.workloadPercentage}
                                    status="exception"
                                    format={(percent) => `${percent}% Overloaded`}
                                />
                            </Space>
                        </div>

                        <Divider />

                        {/* Recommended Employee */}
                        <div>
                            <h4>Recommended Employee</h4>
                            <Space direction="vertical" size={0} style={{ width: '100%' }}>
                                <Space>
                                    <strong>{currentRecommendation.recommendation.name}</strong>
                                    <Tag color="blue">{currentRecommendation.recommendation.role}</Tag>
                                </Space>
                                <Progress
                                    percent={currentRecommendation.recommendation.currentWorkloadPercentage}
                                    format={(percent) => `${percent}% Current Workload`}
                                />
                                <span style={{ fontSize: '12px', color: '#666' }}>
                                    Skills: {currentRecommendation.recommendation.skillMatchPercentage}% match
                                </span>
                                <span style={{ fontSize: '12px', color: '#666' }}>
                                    Recommendation Score: <Tag color="green">{currentRecommendation.score}%</Tag>
                                </span>
                            </Space>
                        </div>

                        <Divider />

                        {/* All Candidates */}
                        {currentRecommendation.allCandidates && currentRecommendation.allCandidates.length > 1 && (
                            <div>
                                <h4>Other Candidates</h4>
                                <Table
                                    dataSource={currentRecommendation.allCandidates.slice(1)}
                                    columns={[
                                        { title: 'Name', dataIndex: 'name', key: 'name' },
                                        {
                                            title: 'Score',
                                            dataIndex: 'score',
                                            key: 'score',
                                            render: (score) => <Tag>{score}%</Tag>
                                        },
                                        {
                                            title: 'Workload',
                                            dataIndex: 'workloadPercentage',
                                            key: 'workload',
                                            render: (wl) => `${wl}%`
                                        }
                                    ]}
                                    pagination={false}
                                    size="small"
                                />
                            </div>
                        )}

                        {/* High Priority Confirmation */}
                        {requiresConfirmation && (
                            <Alert
                                message="High Priority Task"
                                description="This is a high-priority task. Please confirm the reassignment."
                                type="warning"
                                showIcon
                            />
                        )}
                    </Space>
                )}
            </Modal>
        </div>
    );
};

export default SmartReassignmentDashboard;

import React, { useState, useEffect } from 'react';
import { List, Button, Input, Space, Popconfirm, Avatar, Tooltip, message, Spin, Empty } from 'antd';
import { SendOutlined, DeleteOutlined, LikeOutlined } from '@ant-design/icons';
import axios from 'axios';
import moment from 'moment';

/**
 * SpaceComments Component
 * Discussion and collaboration comments within a space
 */
const SpaceComments = ({ spaceId, currentUser }) => {
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [newComment, setNewComment] = useState('');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    loadComments();
    const interval = setInterval(loadComments, 10000); // Poll every 10s
    return () => clearInterval(interval);
  }, [spaceId]);

  const loadComments = async () => {
    setLoading(true);
    try {
      const response = await axios.get(
        `/api/spaces/${spaceId}/comments`,
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      setComments(response.data.data || []);
    } catch {
      console.error('Failed to load comments');
    } finally {
      setLoading(false);
    }
  };

  const handleAddComment = async () => {
    if (!newComment.trim()) {
      message.warning('Please enter a comment');
      return;
    }

    setSubmitting(true);
    try {
      await axios.post(
        `/api/spaces/${spaceId}/comments`,
        { text: newComment },
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );

      setNewComment('');
      loadComments();
      message.success('Comment added');
    } catch {
      message.error('Failed to add comment');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteComment = async (commentId) => {
    try {
      await axios.delete(
        `/api/spaces/${spaceId}/comments/${commentId}`,
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );

      loadComments();
      message.success('Comment deleted');
    } catch {
      message.error('Failed to delete comment');
    }
  };

  return (
    <div className="space-comments">
      <h4>💬 Comments</h4>

      <Spin spinning={loading}>
        {comments.length === 0 ? (
          <Empty description="No comments yet" />
        ) : (
          <List
            dataSource={comments}
            renderItem={(comment) => (
              <List.Item key={comment._id}>
                <List.Item.Meta
                  avatar={<Avatar src={comment.author.avatar}>👤</Avatar>}
                  title={
                    <Space>
                      <span>{comment.author.name}</span>
                      <Tooltip title={moment(comment.createdAt).format('YYYY-MM-DD HH:mm:ss')}>
                        <span style={{ color: '#999', fontSize: '12px' }}>
                          {moment(comment.createdAt).fromNow()}
                        </span>
                      </Tooltip>
                    </Space>
                  }
                  description={<p>{comment.text}</p>}
                />
                <Space>
                  {comment.author._id === currentUser._id && (
                    <Popconfirm
                      title="Delete comment?"
                      onConfirm={() => handleDeleteComment(comment._id)}
                    >
                      <Button type="text" size="small" danger icon={<DeleteOutlined />} />
                    </Popconfirm>
                  )}
                </Space>
              </List.Item>
            )}
          />
        )}
      </Spin>

      {/* Add comment */}
      <div style={{ marginTop: 16, paddingTop: 16, borderTop: '1px solid #f0f0f0' }}>
        <Space direction="vertical" style={{ width: '100%' }}>
          <Input.TextArea
            rows={3}
            placeholder="Add a comment..."
            value={newComment}
            onChange={(e) => setNewComment(e.target.value)}
            onPressEnter={(e) => {
              if (e.ctrlKey || e.metaKey) {
                handleAddComment();
              }
            }}
          />
          <Button
            type="primary"
            icon={<SendOutlined />}
            loading={submitting}
            onClick={handleAddComment}
          >
            Comment
          </Button>
        </Space>
      </div>
    </div>
  );
};

export default SpaceComments;

import React, { useState, useEffect } from 'react';
import { Tabs, Spin, message } from 'antd';
import axios from 'axios';
import './SpaceEditor.css';
import NotesEditor from './editors/NotesEditor';
import WhiteboardEditor from './editors/WhiteboardEditor';
import MindMapEditor from './editors/MindMapEditor';
import SpaceComments from './SpaceComments';
import useSpaceWebSocket from '../../hooks/useSpaceWebSocket';

/**
 * SpaceEditor Component
 * Main editor with tabs for Notes, Whiteboard, and Mind Map
 */
const SpaceEditor = ({ space, currentUser }) => {
  const [content, setContent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('notes');
  const [isSaving, setIsSaving] = useState(false);
  const [lastSaved, setLastSaved] = useState(null);

  // Initialize WebSocket connection
  const { 
    isConnected, 
    activeUsers, 
    cursors, 
    typingUsers,
    sendUpdate
  } = useSpaceWebSocket(space._id, currentUser._id);

  useEffect(() => {
    loadContent();
  }, [space._id]);

  // Autosave every 30 seconds
  useEffect(() => {
    if (!content) return;

    const autoSaveInterval = setInterval(() => {
      handleAutosave();
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, [content, space._id]);

  const loadContent = async () => {
    setLoading(true);
    try {
      const response = await axios.get(
        `/api/spaces/${space._id}`,
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      
      setContent(response.data.data.content);
    } catch (error) {
      message.error('Failed to load space content');
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleAutosave = async () => {
    if (!content) return;

    try {
      await axios.post(
        `/api/spaces/${space._id}/autosave`,
        {
          contentJson: content.contentJson,
          textContent: content.textContent,
          drawingData: content.drawingData,
          mindmapData: content.mindmapData
        },
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      
      setLastSaved(new Date());
      
      // Broadcast update to other users
      sendUpdate({
        contentType: content.contentType,
        contentJson: content.contentJson,
        textContent: content.textContent,
        drawingData: content.drawingData,
        mindmapData: content.mindmapData,
        isAutoSave: true
      });
    } catch (error) {
      console.error('Autosave failed:', error);
    }
  };

  const handleSaveExplicitly = async (updatedContent, editSummary) => {
    setIsSaving(true);
    try {
      const response = await axios.patch(
        `/api/spaces/${space._id}/content`,
        {
          contentType: updatedContent.contentType,
          contentJson: updatedContent.contentJson,
          textContent: updatedContent.textContent,
          drawingData: updatedContent.drawingData,
          mindmapData: updatedContent.mindmapData,
          editSummary,
          isMajorVersion: true
        },
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      
      setContent(response.data.data);
      setLastSaved(new Date());
      message.success('Changes saved');
      
      // Broadcast to other users
      sendUpdate({
        ...updatedContent,
        isMajorVersion: true,
        editSummary
      });
    } catch (error) {
      message.error('Failed to save changes');
      console.error(error);
    } finally {
      setIsSaving(false);
    }
  };

  if (loading) return <Spin size="large" style={{ display: 'flex', justifyContent: 'center', marginTop: 100 }} />;

  const editorProps = {
    content,
    setContent,
    onSave: handleSaveExplicitly,
    isConnected,
    activeUsers,
    cursors,
    typingUsers,
    currentUser,
    isSaving
  };

  return (
    <div className="space-editor">
      <div className="editor-toolbar">
        <div className="toolbar-left">
          <h3>{space.title}</h3>
          {isConnected && (
            <span className="connection-status">🟢 Live ({activeUsers.length} user{activeUsers.length !== 1 ? 's' : ''})</span>
          )}
          {!isConnected && (
            <span className="connection-status">⚪ Offline</span>
          )}
        </div>
        <div className="toolbar-right">
          {lastSaved && (
            <span className="last-saved">Last saved: {lastSaved.toLocaleTimeString()}</span>
          )}
        </div>
      </div>

      <div className="editor-main">
        <div className="editor-content">
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            items={[
              {
                key: 'notes',
                label: '📝 Notes',
                children: <NotesEditor {...editorProps} />
              },
              {
                key: 'whiteboard',
                label: '✏️ Whiteboard',
                children: <WhiteboardEditor {...editorProps} />
              },
              {
                key: 'mindmap',
                label: '🧠 Mind Map',
                children: <MindMapEditor {...editorProps} />
              }
            ]}
          />
        </div>

        {/* Comments sidebar */}
        <div className="editor-sidebar">
          <SpaceComments
            spaceId={space._id}
            currentUser={currentUser}
          />
        </div>
      </div>
    </div>
  );
};

export default SpaceEditor;

import React, { useState, useEffect } from 'react';
import { Modal, List, Button, Select, Space, Popconfirm, Spin, message, Avatar, Tag } from 'antd';
import { UserAddOutlined, DeleteOutlined, LockOutlined } from '@ant-design/icons';
import axios from 'axios';

/**
 * SpaceMembers Component
 * Manage access control and member roles
 */
const SpaceMembers = ({ space, visible, onClose }) => {
  const [members, setMembers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [addingMember, setAddingMember] = useState(false);
  const [selectedUserId, setSelectedUserId] = useState(null);
  const [selectedRole, setSelectedRole] = useState('EDITOR');
  const [users, setUsers] = useState([]);

  useEffect(() => {
    if (visible) {
      loadMembers();
      loadUsers();
    }
  }, [visible, space._id]);

  const loadMembers = async () => {
    setLoading(true);
    try {
      const response = await axios.get(
        `/api/spaces/${space._id}/members`,
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      setMembers(response.data.data || []);
    } catch {
      message.error('Failed to load members');
    } finally {
      setLoading(false);
    }
  };

  const loadUsers = async () => {
    try {
      const response = await axios.get(
        '/api/users',
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      setUsers(response.data.data || []);
    } catch {
      console.error('Failed to load users');
    }
  };

  const handleAddMember = async () => {
    if (!selectedUserId) {
      message.warning('Please select a user');
      return;
    }

    setAddingMember(true);
    try {
      await axios.post(
        `/api/spaces/${space._id}/members`,
        { userId: selectedUserId, role: selectedRole },
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );

      loadMembers();
      setSelectedUserId(null);
      setSelectedRole('EDITOR');
      message.success('Member added');
    } catch (error) {
      message.error(error.response?.data?.message || 'Failed to add member');
    } finally {
      setAddingMember(false);
    }
  };

  const handleUpdateRole = async (memberId, newRole) => {
    try {
      await axios.patch(
        `/api/spaces/${space._id}/members/${memberId}`,
        { role: newRole },
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );

      loadMembers();
      message.success('Role updated');
    } catch {
      message.error('Failed to update role');
    }
  };

  const handleRemoveMember = async (memberId) => {
    try {
      await axios.delete(
        `/api/spaces/${space._id}/members/${memberId}`,
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );

      loadMembers();
      message.success('Member removed');
    } catch {
      message.error('Failed to remove member');
    }
  };

  const roleColors = { OWNER: 'red', EDITOR: 'blue', COMMENTER: 'gold', VIEWER: 'default' };

  return (
    <Modal
      title={`👥 Space Members - ${space.title}`}
      open={visible}
      onCancel={onClose}
      width={500}
      footer={null}
    >
      <Spin spinning={loading}>
        {/* Add member */}
        <div style={{ marginBottom: 24, padding: '16px', backgroundColor: '#fafafa', borderRadius: '4px' }}>
          <h4>Add Member</h4>
          <Space style={{ width: '100%' }}>
            <Select
              placeholder="Select user"
              value={selectedUserId}
              onChange={setSelectedUserId}
              style={{ flex: 1 }}
              options={users
                .filter(u => !members.some(m => m.user.id === u._id))
                .map(u => ({
                  label: u.name,
                  value: u._id
                }))}
            />
            <Select
              value={selectedRole}
              onChange={setSelectedRole}
              options={[
                { label: 'Owner', value: 'OWNER' },
                { label: 'Editor', value: 'EDITOR' },
                { label: 'Commenter', value: 'COMMENTER' },
                { label: 'Viewer', value: 'VIEWER' }
              ]}
            />
            <Button
              type="primary"
              icon={<UserAddOutlined />}
              onClick={handleAddMember}
              loading={addingMember}
            >
              Add
            </Button>
          </Space>
        </div>

        {/* Members list */}
        <List
          dataSource={members}
          renderItem={(member) => (
            <List.Item
              key={member.id}
              actions={[
                <Select
                  value={member.role}
                  onChange={(value) => handleUpdateRole(member.id, value)}
                  options={[
                    { label: 'Owner', value: 'OWNER' },
                    { label: 'Editor', value: 'EDITOR' },
                    { label: 'Commenter', value: 'COMMENTER' },
                    { label: 'Viewer', value: 'VIEWER' }
                  ]}
                  style={{ width: '100px' }}
                />,
                member.role !== 'OWNER' && (
                  <Popconfirm
                    title="Remove member?"
                    onConfirm={() => handleRemoveMember(member.id)}
                  >
                    <Button danger icon={<DeleteOutlined />} type="text" size="small" />
                  </Popconfirm>
                )
              ]}
            >
              <List.Item.Meta
                avatar={<Avatar src={member.user.avatar} icon="👤" />}
                title={member.user.name}
                description={
                  <Space size="small">
                    <Tag color={roleColors[member.role]}>
                      {member.role === 'OWNER' && <LockOutlined />}
                      {member.role}
                    </Tag>
                    <span>{member.contributionCount} edits</span>
                  </Space>
                }
              />
            </List.Item>
          )}
        />
      </Spin>
    </Modal>
  );
};

export default SpaceMembers;

import React, { useState, useEffect } from 'react';
import { Tabs, Button, Card, Row, Col, Space, Modal, Form, Input, Select, Popconfirm, Tooltip, Empty, Spin, message } from 'antd';
import { PlusOutlined, DeleteOutlined, EditOutlined, TeamOutlined, HistoryOutlined } from '@ant-design/icons';
import axios from 'axios';
import { useProject } from '../../context/ProjectContext';
import { useAuth } from '../../context/AuthContext';
import './Spaces.css';
import SpaceEditor from './SpaceEditor';
import SpaceMembers from './SpaceMembers';

/**
 * Spaces Component
 * Main hub for collaborative note-taking, drawing, and mind mapping
 */
const Spaces = () => {
  const { currentProject } = useProject();
  const { user } = useAuth();
  const projectId = currentProject?._id;
  const currentUser = user;
  
  const [spaces, setSpaces] = useState([]);
  const [selectedSpace, setSelectedSpace] = useState(null);
  const [activeTab, setActiveTab] = useState('list');
  const [loading, setLoading] = useState(false);
  const [createModalVisible, setCreateModalVisible] = useState(false);
  const [membersModalVisible, setMembersModalVisible] = useState(false);
  const [form] = Form.useForm();

  // Load spaces on mount
  useEffect(() => {
    loadSpaces();
  }, [projectId]);

  const loadSpaces = async () => {
    setLoading(true);
    try {
      const response = await axios.get(
        `/api/spaces/project/${projectId}`,
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      setSpaces(response.data.data || []);
    } catch (error) {
      message.error('Failed to load spaces');
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateSpace = async (values) => {
    if (!projectId) {
      message.error('Please select a project first');
      return;
    }
    
    if (!currentUser) {
      message.error('Please log in first');
      return;
    }

    try {
      const response = await axios.post(
        '/api/spaces',
        {
          projectId,
          ...values
        },
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      
      setSpaces([response.data.data, ...spaces]);
      setCreateModalVisible(false);
      form.resetFields();
      message.success('Space created successfully');
    } catch (error) {
      console.error('Create space error:', error);
      message.error(error.response?.data?.message || 'Failed to create space');
    }
  };

  const handleDeleteSpace = async (spaceId) => {
    try {
      await axios.delete(
        `/api/spaces/${spaceId}`,
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      
      setSpaces(spaces.filter(s => s._id !== spaceId));
      if (selectedSpace?._id === spaceId) {
        setSelectedSpace(null);
        setActiveTab('list');
      }
      message.success('Space archived successfully');
    } catch (error) {
      message.error(error.response?.data?.message || 'Failed to archive space');
    }
  };

  // Render list view
  const renderListView = () => {
    if (loading) return <Spin />;
    if (spaces.length === 0) {
      return (
        <Empty
          description="No spaces yet"
          style={{ marginTop: 48 }}
          extra={
            <Button type="primary" onClick={() => setCreateModalVisible(true)}>
              Create First Space
            </Button>
          }
        />
      );
    }

    return (
      <Row gutter={[16, 16]}>
        {spaces.map(space => (
          <Col xs={24} sm={12} lg={8} key={space._id}>
            <Card
              hoverable
              className="space-card"
              onClick={() => {
                setSelectedSpace(space);
                setActiveTab('editor');
              }}
            >
              <div className="space-card-header">
                <h3>{space.title}</h3>
                <Space size="small">
                  <Tooltip title="Members">
                    <Button
                      type="text"
                      size="small"
                      icon={<TeamOutlined />}
                      onClick={(e) => {
                        e.stopPropagation();
                        setSelectedSpace(space);
                        setMembersModalVisible(true);
                      }}
                    >
                      {space.contributorCount || 0}
                    </Button>
                  </Tooltip>
                  <Popconfirm
                    title="Archive Space?"
                    description="This space will be archived but can be recovered"
                    onConfirm={(e) => {
                      e.stopPropagation();
                      handleDeleteSpace(space._id);
                    }}
                    onClick={(e) => e.stopPropagation()}
                  >
                    <Button type="text" danger size="small" icon={<DeleteOutlined />} />
                  </Popconfirm>
                </Space>
              </div>
              
              {space.description && (
                <p className="space-description">{space.description}</p>
              )}
              
              <div className="space-meta">
                <span>📝 {space.defaultContentType}</span>
                <span>✏️ v{space.versionCount || 1}</span>
                <span>👥 {space.members?.length || 1}</span>
              </div>
            </Card>
          </Col>
        ))}
      </Row>
    );
  };

  return (
    <div className="spaces-container">
      <div className="spaces-header">
        <h2>📝 Shared Spaces</h2>
        <Button
          type="primary"
          icon={<PlusOutlined />}
          onClick={() => setCreateModalVisible(true)}
        >
          New Space
        </Button>
      </div>

      <Tabs
        activeKey={activeTab}
        onChange={setActiveTab}
        items={[
          {
            key: 'list',
            label: 'All Spaces',
            children: renderListView()
          },
          ...(selectedSpace ? [
            {
              key: 'editor',
              label: `✏️ ${selectedSpace.title}`,
              children: (
                <SpaceEditor
                  space={selectedSpace}
                  currentUser={currentUser}
                  onUpdate={(updated) => {
                    setSelectedSpace(updated);
                    setSpaces(spaces.map(s => s._id === updated._id ? updated : s));
                  }}
                />
              )
            }
          ] : [])
        ]}
      />

      {/* Create Space Modal */}
      <Modal
        title="Create New Space"
        open={createModalVisible}
        onOk={() => form.submit()}
        onCancel={() => {
          setCreateModalVisible(false);
          form.resetFields();
        }}
      >
        {!projectId && (
          <div style={{ color: 'red', marginBottom: 16 }}>
            ⚠️ No project selected. Please select a project from the dashboard first.
          </div>
        )}
        <Form form={form} layout="vertical" onFinish={handleCreateSpace}>
          <Form.Item
            name="title"
            label="Space Title"
            rules={[{ required: true, message: 'Please enter space title' }]}
          >
            <Input placeholder="e.g., Project Sprint Notes" />
          </Form.Item>

          <Form.Item
            name="description"
            label="Description (Optional)"
          >
            <Input.TextArea rows={3} placeholder="What is this space for?" />
          </Form.Item>

          <Form.Item
            name="defaultContentType"
            label="Default Content Type"
            initialValue="TEXT"
          >
            <Select>
              <Select.Option value="TEXT">📝 Notes (Rich Text)</Select.Option>
              <Select.Option value="WHITEBOARD">✏️ Whiteboard (Drawing)</Select.Option>
              <Select.Option value="MINDMAP">🧠 Mind Map (Nodes & Connections)</Select.Option>
            </Select>
          </Form.Item>
        </Form>
      </Modal>

      {/* Members Modal */}
      {selectedSpace && (
        <SpaceMembers
          space={selectedSpace}
          visible={membersModalVisible}
          onClose={() => setMembersModalVisible(false)}
          onUpdate={(updated) => {
            setSelectedSpace(updated);
            setSpaces(spaces.map(s => s._id === updated._id ? updated : s));
          }}
        />
      )}
    </div>
  );
};

